+
+      // TD error
+      const tdError = targetQ - currentQ;
+      const loss = tdError * tdError;
+      totalLoss += loss;
+
+      // Accumulate gradients
+      this.accumulateGradients(gradients, exp.state, exp.action, tdError);
+    }
+
